"""
MKT Context Commentary — Acts chapters 22–24
Run: python3 scripts/zc-context-acts-22-24.py

Source data used:
- data/interlinear/acts.json
- data/translation/draft/mediating/acts.json

Key decisions in this range:
- Acts 22 is Paul's third autobiographical account (alongside Acts 9 and 26);
  the differences between accounts are variation in oral re-telling, not
  contradiction; the Jerusalem speech adapts the story for a Jewish audience
  by emphasizing Paul's Jewish credentials throughout.
- Herod Agrippa I died 44 CE; the events of Acts 22-26 are c. 57-59 CE under
  procurator Felix (52-60 CE) and then Festus (60-62 CE).
- Tertullus (ch24): his speech follows the classical Roman forensic structure
  (captatio benevolentiae + narratio + probatio); cited as literary evidence
  of Luke's familiarity with Hellenistic rhetoric.
- Felix and Drusilla: their personal history (Drusilla left her first husband
  Azizus of Emesa to marry Felix) is confirmed by Josephus Ant. 20.7.1-2
  and is relevant to Paul's speech about self-control and righteousness.
- The collection (ch24:17): Luke's only reference to Paul's major project
  that dominates 2 Cor 8-9, Rom 15:25-28, and 1 Cor 16:1-4.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS = {
  "22": {
    "1": "<p><strong>Andres adelphoi kai pateres, akousate mou tēs pros hymas nyn apologias</strong> ('Brothers and fathers, hear my defense'): <em>apologia</em> (defense speech) carries both the everyday sense of self-defense and the philosophical sense — Plato's <em>Apology</em> presents Socrates's defense of his life before hostile judges. Luke's use of <em>apologia</em> in Paul's speeches (22:1; 25:16; 26:2) frames Paul as an apostolic Socrates: a man of conviction before accusers who cannot comprehend him. The address 'brothers and fathers' (<em>adelphoi kai pateres</em>) echoes Stephen's opening (7:2) — placing Paul in the same tradition of the prophet speaking to the covenant community he loves but has lost.</p>",

    "2": "<p><strong>Tē Hebraidi dialektō</strong> ('in the Hebrew dialect/Aramaic'): first-century Palestinian 'Hebrew' virtually always means Aramaic — the spoken vernacular, not classical biblical Hebrew. The crowd's response — 'they became even quieter' (<em>mallon pareschon hēsychian</em>) — shows the strategic value of the language choice: Aramaic signals insider status, Jewish solidarity, and removes the suspicion that Paul has become culturally Hellenized. The same rhetorical move as Peter's 'fellow Israelites' at Pentecost (2:14) — establishing shared identity before making a challenging claim.</p>",

    "3": "<p><strong>Anatetrammenos en tē polei tautē para tous podas Gamaliēl</strong> ('brought up in this city at the feet of Gamaliel'): Paul's three-stage identity — born in Tarsus (Diaspora), raised in Jerusalem (center), educated under Gamaliel (elite) — positions him as the most impeccably Jewish of Jews despite Diaspora birth. Gamaliel I was one of the great sages of the first century, grandson of Hillel — the most respected rabbinic lineage. 'At the feet of' (<em>para tous podas</em>) is the standard posture for a student seated before a teacher; it is the posture of Mary in Luke 10:39. Paul's rabbinic education under Gamaliel was the equivalent of elite legal training in first-century Jewish terms.</p>",

    "4": "<p><strong>Hēn hodon ediōxa achri thanatou</strong> ('I persecuted this Way to the death'): 'the Way' (<em>hē hodos</em>) is the early Christian self-designation appearing seven times in Acts (9:2; 19:9, 23; 22:4; 24:14, 22; 26:4). The metaphor of <em>hodos</em> (road/way) carries OT resonance — the way of the LORD (Ps 25:4; Isa 40:3; Jer 6:16) — applied to the messianic community. Paul's confession 'to the death' (<em>achri thanatou</em>) does not minimize the consequences of his former actions; the candor is strategic — establishing the magnitude of his pre-conversion zeal makes the conversion itself more inexplicable by any human cause.</p>",

    "5": "<p><strong>Ho archiereus kai pan to presbyterion</strong> ('the high priest and the whole council of elders'): Paul calls his former principals as character witnesses for his pre-conversion identity. The irony is deliberate: the very council now prosecuting him authorized his persecution — the same men who commissioned him to Damascus are now his accusers. The letters from Damascus also attest to the Jerusalem council's authority over diaspora Jewish communities, a jurisdictional reach that shows the scope of Paul's former assignment.</p>",

    "6": "<p><strong>Peri mesēmbrian</strong> ('about noon'): the midday timing — when the sun is at maximum brilliance — makes the heavenly light's surpassing of natural sunlight all the more significant. Paul adds this detail in his Jerusalem speech that is absent from Luke's third-person account in ch.9. The noonday timing is significant in Hebrew Scripture: noon-hour divine appearances carry a sense of unmistakable clarity (cf. Amos 8:9; Isa 18:4). The specificity of the time detail is a realism marker suggesting firsthand report.</p>",

    "7": "<p><strong>Saoul Saoul, ti me diōkeis</strong> ('Saul! Saul! Why do you persecute me?'): the double address — 'Saul, Saul' — is the Hebrew/Aramaic form of urgent personal directness, used in moments of divine confrontation: 'Abraham, Abraham!' (Gen 22:11), 'Moses, Moses!' (Exod 3:4), 'Samuel, Samuel!' (1 Sam 3:10). In each case the double address precedes a decisive divine commissioning. The question 'why do you persecute me?' identifies Christ with the persecuted community — to persecute the church is to persecute Christ himself. This is the most theologically loaded phrase in the Damascus road accounts.</p>",

    "8": "<p><strong>Iēsous ho Nazōraios</strong> ('Jesus the Nazarene'): the geographic-historical designation preserves the particularity of the risen Christ's identity. 'Jesus of Nazareth' is the formula used consistently in Acts (2:22; 3:6; 4:10; 6:14; 22:8; 24:5; 26:9) — anchoring the risen Lord's identity to his historical humanity. The persecutor is confronted not by an abstract divine principle but by a specific, named, historically located person who has proven stronger than death and who identifies himself with the victims of Saul's violence.</p>",

    "9": "<p><strong>Hoi de syn emoi ontes to men phōs etheasanto</strong> ('those with me saw the light'): the apparent tension with Acts 9:7 ('hearing the sound but seeing no one') is a perception-level distinction in the Greek vocabulary of hearing. Acts 9:7 says they heard the sound (<em>phōnē</em> = sound); Acts 22:9 says they did not hear the voice (<em>phōnē</em> = intelligible speech). Greek <em>phōnē</em> can mean both audible phenomenon and communicative speech; the companions experienced the former but not the latter. Paul alone received the address — a distinction between the auditory phenomenon (sound/light) and the communicative content (intelligible speech to Paul).</p>",

    "10": "<p><strong>Anastas poreuthēti eis Damaskon</strong> ('rise and go to Damascus'): the divine direction is specific, immediate, and geographic — not a mystical illumination but an itinerary. The pattern follows the OT commissioning structure: encounter → prostration → divine address → specific destination → sending. Paul's question — 'What shall I do, Lord?' (<em>ti poiēsō, Kyrie</em>) — is the convert's first act of submitted discipleship. The willingness to receive direction ('what shall I do?') marks the radical reorientation of a formerly self-directed zealot.</p>",

    "11": "<p><strong>Hōs de ouk eneblepon apo tēs doxēs tou phōtos ekeinou</strong> ('since I could not see because of the glory of that light'): Paul's blindness is explicitly attributed to divine glory (<em>doxa</em>) — theophanic language. The glory that overwhelmed Isaiah's vision (Isa 6:5) and prostrated Ezekiel (Ezek 1:28) here blinds the persecutor. Being led by the hand (<em>cheiragōgoumenoi</em>) is a posture of complete dependence — the man who had arrested and imprisoned others is now led as a helpless dependent. The reversal is total and physical before it is theological.</p>",

    "12": "<p><strong>Ananias eulabes kata ton nomon, martyroumenos hypo pantōn tōn katoikountōn Ioudaiōn</strong> ('Ananias, devout according to the law, well-spoken of by all the Jews living there'): in Paul's Jerusalem speech Ananias's credentials are emphasized differently from Acts 9 (where he is simply 'a disciple'). Here he is Torah-observant and respected by the Jewish community — Jewish credentials for a Gentile audience. The commission Paul received came through a scrupulously observant Jewish mediator, not a Hellenized apostate. The emphasis refutes any claim that Paul's mission originated in apostasy from Israel.</p>",

    "13": "<p><strong>Ho adelphos Saoul, anablepson</strong> ('Brother Saul, receive your sight'): Ananias addresses Paul as 'brother' — acknowledging him as a member of the Jewish community before addressing him as a disciple. The restoration of sight enacts Isa 42:7 ('to open eyes that are blind') — the Servant's mission applied to Paul himself before he will carry it to the Gentiles. The physical healing is the first sign of the new creation that has occurred; the restored eyes will see differently, as Luke's narrative will demonstrate.</p>",

    "14": "<p><strong>Ho dikaios</strong> ('the Righteous One'): Ananias's designation of Jesus is one of the earliest Christological titles in Acts, appearing in Peter's Pentecost speech (3:14, 'the Holy and Righteous One') and Stephen's speech (7:52). The title draws from Isa 53:11 ('the righteous one, my servant, will justify many') and the <em>Book of Enoch</em>'s 'Righteous One' for the heavenly Son of Man. The title is Ananias's, not Paul's own invention — confirming that Paul received the earliest Christological traditions through the community he had persecuted.</p>",

    "15": "<p><strong>Martys autō pros pantas anthrōpous</strong> ('his witness to all people'): the universal scope of Paul's witness mandate — <em>pros pantas anthrōpous</em> ('to all people') — is stated explicitly at his commissioning. The Gentile mission is not a later development or accommodation; it is inscribed in Paul's original calling. His speaking before the hostile Jerusalem crowd is itself an act of witness 'to all people' — including the people most resistant to his message.</p>",

    "16": "<p><strong>Baptisai kai apolousai tas hamartias sou epikalesamenos to onoma autou</strong> ('be baptized and wash away your sins, calling on his name'): the baptismal formula connects three elements — the physical act (baptism), the spiritual effect (washing of sins), and the spiritual instrument (calling on the name). The middle voice <em>apolousai</em> (wash away for yourself / have yourself washed) emphasizes the recipient's reception of an external act rather than self-cleansing. The 'calling on the name' formula connects to Joel 2:32 (Acts 2:21) — the same OT promise that structured Peter's Pentecost proclamation.</p>",

    "17": "<p><strong>Genesthai me en ekstasei</strong> ('I fell into a trance'): <em>ekstasis</em> is the technical term for visionary states in Acts (10:10; 11:5) — a standing-outside-oneself in which divine communication occurs. Paul's temple trance appears only in this speech, not in Acts 9's narrative — additional biographical detail available in Paul's firsthand account. The setting is striking: in the very temple that represents Jewish covenantal identity, Paul receives a commission to leave Jerusalem. The center of Israel's worship is where Paul receives his mandate for those furthest from that covenant.</p>",

    "18": "<p><strong>Exelthe en tachei ex Ierousalēm</strong> ('leave Jerusalem quickly'): the risen Christ's foreknowledge of Jerusalem's rejection anticipates the entire Acts narrative. The city that killed the prophets (Luke 13:34) will not receive Paul's testimony; the commission is redirected outward. <em>Martyria</em> (testimony/witness) is the technical term; Jerusalem's rejection of testimony is foreseen and does not negate the mission — it redirects it.</p>",

    "19": "<p>Paul's interjection — 'Lord, they know that I used to imprison and beat those who believed in you' — reveals his pastoral logic: his past as persecutor should make him a maximally credible witness to Jerusalem's community, who knew his former zeal. The argument has a compelling structure: if a man who imprisoned and beat believers now proclaims the resurrection, the only explanation is the truth of the thing he proclaims. The Lord's response (v.21) overrides this pastoral reasoning with a broader divine purpose — 'Go, for I will send you to the Gentiles.'</p>",

    "20": "<p><strong>Kai hote exechynneto to haima Stephanou tou martyros sou</strong> ('when the blood of your witness Stephen was shed'): <em>martys</em> applied to Stephen is the first use in Acts approaching the later technical meaning of 'martyr' — one who witnesses unto death. Paul's confession — 'consenting and guarding the clothes of those killing him' (<em>syneurokōn kai phylassōn ta himatia tōn anairountōn auton</em>) — is his most explicit personal acknowledgment of guilt, placed here in the account of his conversion and his own experience of the forgiving encounter with the Risen One.</p>",

    "21": "<p><strong>Hoti egō eis ethna makran exapostelō se</strong> ('for I will send you far away to the Gentiles'): 'far away' (<em>makran</em>) echoes Isa 57:19 ('peace to those far and near') and Eph 2:13's vocabulary for Gentile distance from the covenant. The Gentile commission is spoken from the Jerusalem temple — the most sacred Jewish space — to the most persecuting-turned-apostle. The irony is total: the center of Jewish covenantal worship is where Paul receives his mandate for those furthest from that covenant.</p>",

    "22": "<p><strong>Hēkouon de autou achri toutou tou logou</strong> ('they listened to him until this word'): 'Gentiles' (<em>ethnesin</em>) is the trigger-word that ends the crowd's silence. The audience had settled to hear a Jewish defense; the announcement of a universal mission to Gentiles — Israel's historic outsiders — ruptures the listening. <em>Aire apo tēs gēs ton toiouton</em> ('take such a person from the earth') echoes the crowd's demand for Jesus (Luke 23:18, 'take him away!') — Luke's deliberate parallel between the trials of Jesus and Paul.</p>",

    "23": "<p><strong>Rhiptountōn ta himatia kai koniorton ballontōn eis ton aera</strong> ('throwing off their cloaks and flinging dust into the air'): the gesture-complex — stripping outer garments and dust-throwing — is a theatrical expression of outrage, possibly involving quasi-ritual gestures of protestation or cursing. The dust-throwing may echo the mourning-gesture of covering oneself with dust (Josh 7:6; 2 Sam 13:19) — here deployed in anger rather than grief. Luke's vivid detail suggests eyewitness or close-source description.</p>",

    "24": "<p><strong>Anazesthai auton mastixin</strong> ('to examine him by flogging'): the Roman interrogation technique of <em>flagellum</em> — a leather whip reinforced with lead weights or bone — was used to extract information from non-citizens and slaves. The tribune acts out of administrative logic: flog the troublemaker until he explains himself. He does not know or consider Paul's legal status at this point. The procedure is technically illegal for a Roman citizen not yet convicted, a fact Paul will invoke at precisely the moment of maximum legal exposure (v.25).</p>",

    "25": "<p><strong>Ei anthrōpon Rhōmaion kai akatakriton exestin hymin mastizein</strong> ('is it lawful to flog a man who is a Roman citizen and uncondemned?'): Paul's timing is exquisite — he speaks at the moment of maximum legal exposure for the tribune, after the order has been given but before the first stroke. <em>Akatakriton</em> (uncondemned/without trial) is the legal term for summary punishment without due process — already invoked in 16:37 at Philippi. The citizen-claim precisely when the procedure is about to begin forces an immediate halt. Roman law (<em>lex Valeria</em> and <em>lex Porcia</em>) prohibited the physical punishment of citizens without trial.</p>",

    "26": "<p><strong>Hora ti melleis poiein</strong> ('watch what you are about to do'): the centurion's warning to the commander shows the chain of accountability activated by the citizenship claim. He recognizes the legal risk before the commander does — he has seen enough of Roman administrative law to know that flogging a citizen is a prosecutable offense. The rapid institutional response to the legal signal — escalate, do not proceed — reflects the Roman military's practical training in liability management.</p>",

    "27": "<p><strong>Rhōmaios ei</strong> ('are you a Roman citizen?'): the tribune's direct challenge; Paul's 'Yes, I am' is legally sufficient. Roman citizenship claims were taken seriously; the legal penalty for false claims was severe enough to make false claims relatively rare, and the penalties for flogging a genuine citizen severe enough to make commanders cautious. Paul's calm affirmation carries both legal weight and the spiritual composure of one whose identity is secured at a level deeper than civic status.</p>",

    "28": "<p><strong>Egō de kai gegennēmai</strong> ('I was born to it'): Paul's birth-citizenship outranks the tribune's purchased citizenship — birth-citizenship was the superior form in Roman social hierarchy. How Paul's family acquired citizenship is not stated; possibilities include Tarsus's civic status, Paul's father's service to Rome, or citizenship granted to a Jewish community in Cilicia. The social inversion is deliberate: the prisoner is socially superior to the officer interrogating him, a fact that changes the entire dynamic of the interaction.</p>",

    "29": "<p><strong>Ho chiliarchos de ephobethe epignous hoti Rhōmaios estin kai hoti auton ēn dedekōs</strong> ('the commander was alarmed when he realized he was a Roman and that he had chained him'): chaining a Roman citizen without due process was itself illegal — the commander has already committed a legal offense before the flogging question even arose. His fear is personal legal exposure, not merely administrative concern. The irony of the power dynamic is complete: the Roman officer who arrested Paul is now more legally vulnerable than the prisoner.</p>",

    "30": "<p><strong>Bouleusē to asphales</strong> ('to find out the certain truth'): <em>asphales</em> (certain/secure) recurs in the legal investigation sections of Acts — the Roman system's insistence on procedural exactness. The tribune's decision to convene the Sanhedrin is his attempt to access Jewish legal expertise — the same kind of referral Pilate made to Herod (Luke 23:7). Roman administrators consistently sought local expertise for disputes arising from religious law; convening the Sanhedrin as a consulting body was within the tribune's authority.</p>"
  },

  "23": {
    "1": "<p><strong>Syneidēsei agathē pepoliteumai tō theō achri tautēs tēs hēmeras</strong> ('I have lived my life before God with a clear conscience to this day'): <em>syneidēsis</em> (conscience) is a Pauline technical term appearing 20 times in his letters (Rom 2:15; 9:1; 1 Cor 8:7; 2 Cor 1:12; 1 Tim 1:5, 19; 2 Tim 1:3). Its presence here confirms Luke's authentic representation of Pauline vocabulary. The cognate <em>pepoliteumai</em> (perfect — 'I have conducted my citizenship/life') uses civic vocabulary: the moral life is public, accountable, a form of civic participation. The claim is bold before the Sanhedrin: Paul does not acknowledge a break in moral continuity between his pre-conversion zeal and his apostolic vocation.</p>",

    "2": "<p><strong>Ho archiereus Ananias</strong>: the high priest Ananias son of Nebedeus served c. AD 47-58 — known from Josephus (<em>Ant.</em> 20.9.2; <em>Wars</em> 2.17.9) as violent, greedy, and pro-Roman, despised by many Jews. His order to strike Paul on the mouth (<em>tuptein autou to stoma</em>) — before any verdict — is a procedural violation of the Sanhedrin's own rules. The Mishnah (<em>Sanhedrin</em> 9.1) required a formal trial before any punishment; Ananias's impulsive order exposes the hypocrisy that Paul will immediately name.</p>",

    "3": "<p><strong>Typsai se mellei ho theos, toiche kekoniamene</strong> ('God is going to strike you, you whitewashed wall!'): the 'whitewashed wall' image echoes Ezekiel 13:10-16, where God condemns the prophets who whitewash a flimsy wall — presenting an appearance of solidity over hollowness. Jesus uses similar imagery in Matt 23:27 ('whitewashed tombs'). Paul's outburst is prophetic denunciation in the OT tradition — naming the gap between the high priest's judicial role and his actual behavior. The prediction ('God is going to strike you') was partially enacted: Ananias was assassinated by Jewish nationalists in AD 66, cut down by those he had exploited.</p>",

    "4": "<p>The bystanders' rebuke — 'how dare you insult God's high priest?' — highlights the tension between office and conduct. The <em>office</em> of high priest deserved honor; the <em>conduct</em> Paul observed deserved rebuke. Paul's response (v.5) handles this tension by appealing to Scripture — 'it is written: do not speak evil of a ruler of your people' (Exod 22:28). He accepts the correction without retracting the substance of his accusation; compliance with Torah even when it works against himself models the very standard the high priest was not meeting.</p>",

    "5": "<p><strong>Ouk ēdein, adelphoi, hoti estin archiereus</strong> ('I did not know, brothers, that he was the high priest'): various explanations have been proposed: genuine disorientation after the previous day's chaos; Paul's poor eyesight (Gal 4:15; 6:11); the high priest's lack of formal vestments in this informal setting; or (most likely read as irony) 'I would not have recognized such a person as high priest by his behavior.' Whatever the reading, Paul responds to the correction by citing Exod 22:28 — grounding his behavior change in scriptural authority, not personal respect for Ananias.</p>",

    "6": "<p><strong>Farisaios ... huios Farisaiōn</strong> ('a Pharisee, the son of Pharisees'): Paul's declaration of Pharisaic identity is not opportunistic but accurate (Phil 3:5 — 'a Pharisee by training'). The resurrection was the genuine center of his message; the Pharisee-Sadducee split on resurrection was the real theological issue at stake. The strategy exploits an existing fault-line — but it is not dishonest: Paul stands in the Pharisaic tradition of resurrection hope that the Sadducees rejected, and the Pharisees recognize it. <em>Elpidos kai anastaseōs nekrōn egō krinomai</em> ('it is concerning hope and the resurrection of the dead that I am being tried') is an accurate theological summary.</p>",

    "7": "<p><strong>Schisma tou plēthous</strong> ('a split of the assembly'): the Sanhedrin's division is Luke's demonstration that the resurrection was a live, contested, divisive issue within Judaism itself — not merely a Christian aberration. Pharisees and Sadducees had irreconcilable positions on bodily resurrection, the existence of angels and spirits, and the nature of human destiny. Paul's strategic declaration puts him in the Pharisaic camp — which was the majority party — on the central question that motivated his entire mission.</p>",

    "8": "<p><strong>Saddoukaioi men gar legousin mē einai anastasin mēte angelon mēte pneuma</strong> ('the Sadducees say there is no resurrection, neither angel nor spirit'): Luke's parenthetical theological summary matches Josephus (<em>Ant.</em> 18.1.4) exactly: 'The Sadducees deny the persistence of the soul after death, as also the rewards of the underworld, including punishments.' The Sadducees' triple denial — no resurrection, no angels, no spirits — appears to have been a principled theological position distinguishing them from Pharisees who affirmed all three based on oral tradition and broader canonical interpretation. The Sadducees restricted authority to the Pentateuch.</p>",

    "9": "<p><strong>Ei de pneuma elalēsen autō ē angelos</strong> ('what if a spirit or an angel has spoken to him?'): the Pharisees' open question is the most theologically generous interpretation of Paul's Damascus experience that a non-believing Pharisee could offer — and it remains within their own worldview. They cannot deny resurrection as a category; they must at least consider that Paul's encounter fits their tradition of divine communication through heavenly mediators. Luke records this concession without suggesting the Pharisees became Christians; their theological solidarity with Paul's claim is real but limited.</p>",

    "10": "<p><strong>Mē diaspassthē ho Paulos hyp' autōn</strong> ('Paul should be torn apart by them'): the physical danger — <em>diaspaō</em> (tear to pieces) — reflects the intensity of the theological dispute turned violent. The tribune's intervention (rescuing Paul again from a Jewish institutional setting) continues the Acts pattern of Roman authority protecting Paul from Jewish mob violence. The paradox of Roman imperial machinery repeatedly rescuing the apostle to the Gentiles is Luke's running comment on divine providence using unexpected instruments.</p>",

    "11": "<p><strong>Tharsei</strong> ('take courage'): the Lord's nocturnal appearance uses vocabulary consistent with the divine commissioning appearances throughout Acts (18:9-10; 27:23-24). <em>Tharsei</em> ('be courageous/confident') is also the word Jesus used to the paralyzed man (Matt 9:2), to the disciples on the stormy lake (Matt 14:27), and to the woman healed of bleeding (Mark 5:34). <em>Dei se kai eis Rhōmēn martyrēsai</em> ('you must testify about me in Rome also'): the divine necessity (<em>dei</em>) structures Paul's entire journey from Jerusalem to Rome — imprisonment, appeals, shipwreck, all within the mandate.</p>",

    "12": "<p><strong>Anathematisantes heautous</strong> ('bound themselves with a solemn oath'): the <em>anathema</em> (solemn curse/ban) was the most serious oath form in Judaism, placing the oath-taker under divine curse if the vow was broken. Binding oneself by <em>anathema</em> not to eat or drink until an action was completed was a recognized practice; if the condition was not met, the oath could be dissolved by a rabbi. The number 'more than forty' (<em>pleiōn tesserakonta</em>) is precise enough to suggest Luke had access to detailed information about the conspiracy — possibly from Paul's own later recounting or from community members who knew the story.</p>",

    "13": "<p>The specificity of 'more than forty' conspirators reflects the kind of concrete detail that comes from sources close to the events. Luke's precision in Acts — troop numbers, journey distances, nautical terms, specific officials' names — is a consistent feature that ancient and modern historians have found consistent with reliable oral and written sourcing.</p>",

    "14": "<p><strong>Anathemati anethematisamen heautous</strong> ('we have bound ourselves with a solemn curse'): the intensive cognate construction (Hebrew absolute-infinitive equivalent in Greek) is the most emphatic form — 'we have absolutely, certainly bound ourselves.' The conspirators approach the chief priests and elders — the same institutional leadership that had been unable to stop Peter and the apostles in chs. 4-5 — now as co-conspirators in another attempt to eliminate the movement's key figure.</p>",

    "15": "<p><strong>Hōs mellontas diaginōskein akribesteron ta peri autou</strong> ('as if you were going to examine his case more carefully'): the conspiracy requires the official judicial body's complicity — the Sanhedrin must request a retrial with a legitimate-sounding pretext. The word <em>akribesteron</em> ('more accurately/exactly') is the very word Felix will use to describe his own knowledge of the Way (24:22 — 'knowing the Way more accurately'). Luke's verbal connections across the trial narratives are deliberate; the word 'accurate' appears in contexts where the truth is being either sought or evaded.</p>",

    "16": "<p><strong>Ho huios tēs adelphēs Paulou</strong> ('the son of Paul's sister'): the only reference to Paul's extended family in the entire NT. The detail is strikingly specific — not 'a relative' but 'the son of his sister.' Paul's nephew had access to both the conspiracy's information and to the barracks where Paul was held — suggesting a family with sufficient social standing to move between Jewish and Roman circles in Jerusalem. Luke does not explain how the nephew learned of the plot; he narrates the providential chain without editorializing.</p>",

    "17": "<p><strong>Eis ton chiliarchon</strong> ('to the commander'): Paul's access to the tribune through the military chain of command — calling a centurion, requesting the centurion escort his nephew, the centurion complying — shows Paul functioning with considerable agency even as a prisoner. The Roman military hierarchy is navigable and responsive to proper requests from persons with appropriate status. Paul operates within the system's logic rather than against it, using the same structures that arrested him to protect his mission's continuation.</p>",

    "18": "<p>The centurion's speech to the commander — 'the prisoner Paul called me and asked me to bring this young man to you' — is a model of institutional communication: factual, deferential, complete. Luke's representations of Roman military communication throughout Acts 22-28 are consistently credible; the detailed knowledge of Roman procedures is one of the features that supports Luke's claim (in the 'we' passages) to firsthand experience of Paul's journey.</p>",

    "19": "<p><strong>Epilabomenos de tēs cheiros autou ho chiliarchos kai anachorēsas kat' idian</strong> ('taking him by the hand and drawing him aside privately'): the intimate gesture — taking the young man by the hand — and the private setting signal the commander's appropriate caution. He takes the information seriously enough to handle it personally and discreetly. His care with the source and the information reflects competent intelligence management; he does not dismiss or minimize the nephew's approach.</p>",

    "20": "<p>The young man's report is specific and carries the urgency of firsthand intelligence: the conspiracy is coordinated (<em>syntithemai</em> = agree together), the number is precise (more than forty), the oath is binding, and the plan is ready for execution tomorrow. His instruction — 'don't give in to them' (<em>mē peisthai autois</em>) — is direct advocacy to the commander. Luke's repetition of the conspiracy details (vv.12-15, then vv.20-21 in the nephew's report) functions as both narrative and documentary confirmation.</p>",

    "21": "<p><strong>Anathemati anethematisan heautous mē phagein mēde piein heōs ou anelōsin auton</strong>: the nephew's exact repetition of the oath-language confirms that he understood what he heard and that the information is reliable. 'Now they are ready and waiting for your consent' (<em>nyn eisin hetoimoi prosdechomenoi tēn apo sou epangelian</em>) — the commander is explicitly told that the conspirators are counting on his cooperation. The information removes the pretense of a judicial inquiry and reveals the ambush plan.</p>",

    "22": "<p><strong>Ekeleuse mēdeni eklaein hoti tauta enephanisas pros me</strong> ('he ordered him to tell no one he had reported this to him'): source protection — the commander ensures the nephew's anonymity. The young man is never named in Luke's account; his anonymity is preserved even in the telling. The secrecy protects both the young man and the effectiveness of the counter-plan: if the conspirators learned their plot was known, they would either abort or modify it.</p>",

    "23": "<p><strong>Stratiotai diakosioi, hippeis hebdomekonta, dexiolabous diakosioi pentēkonta</strong> ('200 soldiers, 70 cavalry, 200 spearmen'): the escort of 470 soldiers for one prisoner is remarkable. <em>Dexiolaboi</em> (spearmen/right-hand men) is a hapax legomenon — a technical term for a specialized auxiliary unit; its specificity supports Luke's access to official records or firsthand military knowledge. The size of the escort reflects either the seriousness of the assassination threat or the tribune's desire to demonstrate Roman efficiency to the governor with a visible transfer.</p>",

    "24": "<p><strong>Ktemē te parastēsai hina te epibibasantes ton Paulon diasōsōsin pros Phēlika ton hēgemona</strong> ('provide horses for Paul and bring him safely to Felix'): Paul's transport by horse rather than walking reflects his legal status — a Roman citizen being transferred for formal trial, not a common prisoner being transported. The word <em>diasōzō</em> (bring safely) is the same word used for salvation from shipwreck (27:44; 28:1) — the commander's legal obligation to deliver the prisoner safely to the governor.</p>",

    "25": "<p><strong>Grapsas epistolēn echousan ton typon touton</strong> ('having written a letter of the following form'): Roman official correspondence followed standardized forms: name + title, addressee + title, greeting (<em>chairein</em>), narrative body, legal conclusion. Whether Luke had access to the actual letter or reconstructed it from Paul's knowledge, the document's form is consistent with Roman official correspondence of the period. Its self-serving revision of events (v.27) is realistic — bureaucrats protect themselves in written records.</p>",

    "26": "<p><strong>Klaudios Lysias tō kratistō hēgemoni Phēliki chairein</strong> ('Claudius Lysias to His Excellency Governor Felix, greetings'): this is the only place in Acts where the tribune's name — Claudius Lysias — is given. The name itself is informative: 'Claudius' suggests his citizenship was obtained under Claudius (41-54 CE); 'Lysias' is Greek. He is a Greco-Roman military officer who purchased his citizenship (22:28) and governs with reasonable competence. <em>Kratistos</em> ('most excellent') was the standard form of address for equestrian-rank officials (Felix held an equestrian appointment).</p>",

    "27": "<p><strong>Sylalemphthenta hypo tōn Ioudaiōn</strong>: Lysias's account slightly reorders the events — he presents himself as knowing Paul's citizenship before rescuing him (whereas Acts 22 shows he learned the citizenship only after ordering the flogging). This self-protective revision in an official report is entirely realistic; administrators in all eras adjust the narrative in official correspondence. Luke records both versions without harmonizing them — the discrepancy between Lysias's letter and the earlier narrative is itself a historical datum about how official reports work.</p>",

    "28": "<p><strong>Eis to synedrion autōn</strong> ('to their Sanhedrin'): Lysias correctly identifies the dispute as a matter of internal Jewish law (<em>peri zētēmatōn tou nomou autōn</em>, 'concerning disputes about their own law'). This conclusion — that Paul's case involves Jewish religious law, not Roman criminal law — anticipates Felix's, Festus's, and Agrippa's identical conclusions. The Roman judicial tradition consistently recognizes that Paul has not committed a Roman crime; political calculation alone prevents his release.</p>",

    "29": "<p><strong>Mēden axion thanatou ē desmōn echonta enklēma</strong> ('having no charge deserving death or imprisonment'): the third of the innocence declarations structuring Acts 22-26 (alongside Festus in 25:25 and Agrippa in 26:31-32). The pattern mirrors the three innocence declarations in the Passion narrative (Luke 23:4, 14, 22 — Pilate's three 'no basis for a charge'). Paul's imprisonment is legally groundless by Roman standards — a fact stated repeatedly and never refuted, making the continued imprisonment a political choice, not a judicial one.</p>",

    "30": "<p><strong>Pempsas pros se kai tois katēgorois parēngeila</strong> ('sending him to you and ordering his accusers'): the formal transfer — sending both the prisoner and his accusers to Felix — is the correct procedure for trans-jurisdictional cases in the Roman system. Trajan's rescript to Pliny (Ep. 10.96-97) shows the same procedure: accusers must appear in person before the governor. The case now enters the provincial governor's jurisdiction, where it will remain for two years (24:27) due to Felix's calculated inaction.</p>",

    "31": "<p><strong>Antipatrida</strong> ('Antipatris'): about 35 miles north of Jerusalem, at the edge of the coastal plain where the Judean foothills end. The night march (probably 10-12 hours through the hill country) placed Paul safely past the danger zone of the narrow Jerusalem-to-coast passes where the ambush would have been set. At Antipatris the infantry could return to Jerusalem (the assassination threat was now past) while cavalry alone could escort Paul the remaining 25 miles to Caesarea.</p>",

    "32": "<p><strong>Tous hippeis apelthein syn autō</strong> ('leaving the cavalry to continue with him'): the troop-reduction at Antipatris is militarily logical — once past the mountain passes where the forty conspirators would have set the ambush, the threat was neutralized. The cavalry alone were more than sufficient to deter any threat on the coastal plain. Luke's attention to the troop-reduction detail — a seemingly incidental logistical note — is consistent throughout the Acts travel accounts with the texture of firsthand or close-source reporting.</p>",

    "33": "<p><strong>Aperidokan kai ton Paulon autō parestēsan</strong> ('they delivered the letter and presented Paul to him'): the formal handover — letter first, then prisoner — follows Roman administrative procedure. The governor's question about province of origin (v.34) establishes personal jurisdiction; Felix confirms his authority and proceeds. In the Roman administrative system, where a person came from determined which governor had jurisdiction; Cilicia was governed from Syria but Paul was arrested in Judea, so Felix accepted jurisdiction.</p>",

    "34": "<p><strong>Apo poias eparchias estin</strong> ('what province he was from'): the jurisdictional question was standard procedure. Felix learns Paul is from Cilicia — which was under the same Syrian provincial structure but geographically distinct. Felix's acceptance of jurisdiction despite the Cilician origin may reflect the fact that Paul was arrested in Judea and the charges arose there. The administrative detail is consistent with Roman provincial law and shows Luke's familiarity with how jurisdictional questions were handled.</p>",

    "35": "<p><strong>En tō praitōriō tou Hērōdou phylassesthai auton</strong> ('to be kept under guard in Herod's praetorium'): the praetorium at Caesarea — Herod the Great's coastal palace — had become the Roman governor's official residence and administrative center. Paul's custody in the praetorium is <em>custodia militaris</em> (military guard) rather than prison confinement — a form appropriate for a Roman citizen awaiting trial. Philippians 1:13 ('throughout the praetorium') may echo Paul's knowledge of this administrative headquarters from the two-year Caesarean imprisonment that follows.</p>"
  },

  "24": {
    "1": "<p><strong>Rhētor Tertullos tis</strong> ('a certain orator named Tertullus'): Tertullus is the first professional advocate (<em>rhētor</em>) explicitly named in Acts. His name is Latin — suggesting a Roman Jew, a Romanized Jew, or a Gentile hired for his rhetorical expertise. The high priest's decision to hire professional legal counsel reflects the seriousness of the case and the inadequacy of the Sanhedrin's own members to argue before a Roman governor in the forensic rhetorical style that Felix would expect. Professional orators trained in Latin and Greek forensic rhetoric were available for hire throughout the empire.</p>",

    "2": "<p><strong>Pollēs eirēnēs tynchanontes dia sou kai katorthōmatōn ginomenōn tō ethnei toutō dia tēs sēs pronoias</strong> ('we enjoy much peace through you and reforms in this nation through your foresight'): the <em>captatio benevolentiae</em> (capture of goodwill) was a required opening in Roman forensic oratory — complimenting the judge on virtues relevant to the case. Tertullus's praise of Felix for 'peace' is historically ironic: Felix's tenure (52-60 CE) was characterized by multiple violent suppressions of social movements, including the Egyptian prophet's movement (Acts 21:38) and the first significant Zealot uprisings. Josephus (<em>Wars</em> 2.13; <em>Ant.</em> 20.8.5) describes Felix as cruel and rapacious. The flattery is formulaic, not factual — and both Tertullus and Felix know it.</p>",

    "3": "<p><strong>Pantē te kai pantachou apodechometha, kratiste Phēlix, meta pasēs eucharistias</strong> ('everywhere and in every way, most excellent Felix, we acknowledge this with all gratitude'): the accumulated superlatives — 'everywhere,' 'in every way,' 'most excellent,' 'all gratitude' — pile up in conventional forensic flattery. Roman forensic oratory required such openings; courts expected them; skilled judges measured speeches by their argumentative quality rather than by their compliments. The density of the flattery signals its conventional, not sincere, character — a performance both parties recognized as such.</p>",

    "4": "<p><strong>Kleptō se epi pleion</strong> ('I do not want to take up too much of your time'): the <em>brevitas</em> topos — claiming brevity before a speech — was a standard rhetorical device (Latin <em>praeteritio</em>). By promising brevity, the orator signals confidence in the case's strength and respect for the judge's time, both of which cultivate goodwill. Tertullus's actual speech is relatively brief; his promise of brevity is kept more consistently than most ancient orators who invoke the convention.</p>",

    "5": "<p><strong>Loimos</strong> ('a plague/pestilence'): a stock insult in ancient rhetoric for political troublemakers and social agitators — Demosthenes had called Aeschines a <em>loimos</em>. <strong>Prōtostatēs</strong> ('ringleader/front-rank man'): a military term for the man in the front rank, used here metaphorically for the leader of a disruptive movement. <strong>Hairesis</strong> ('sect'): the first application of this term to Christians in Acts. In Paul's letters <em>hairesis</em> means 'faction, divisive party' (1 Cor 11:19; Gal 5:20); Tertullus uses it to characterize Christianity as a schismatic faction within Judaism — undermining its claim to be the legitimate fulfillment of Israel's heritage.</p>",

    "6": "<p><strong>Ton hieron epeiresen bebēlōsai</strong> ('he tried to desecrate the temple'): the charge has been downgraded from the original accusation in 21:28 — where the crowd alleged Paul brought Trophimus the Ephesian into the inner courts (an offense punishable by death under both Jewish and Roman law, confirmed by Josephus <em>Wars</em> 6.2.4). By the time of the formal charge, the accusers have shifted to 'tried to desecrate' — a vaguer, attempted offense. The weakening of the specific charge is itself evidence that the original accusation could not be proven.</p>",

    "7": "<p>The verse in some manuscripts adds that Lysias 'with great violence took him from our hands, ordering his accusers to come before you' — a Western text expansion likely added to explain the transition from v.6 to v.8. Most critical editions bracket or omit it. Its insertion shows ancient readers sensed a gap in the speech's logic that needed bridging; Luke's original text apparently moved from the temple-desecration charge directly to 'examine him yourself' without this editorial addition.</p>",

    "8": "<p><strong>Para hou dynēsē autos anakrinas</strong> ('from whom you will be able, by examining him yourself'): Tertullus refers the decisive evidence to Paul himself — an unusual rhetorical confidence. He assumes Felix's examination will confirm the charges. The confidence may be rhetorical bluff, or it may reflect the accusers' expectation that Felix would accept their characterization of Paul as a troublemaker and act accordingly without rigorous investigation. Paul's counter-speech will demolish this expectation by meeting every charge with specific facts.</p>",

    "9": "<p><strong>Synepethento de kai hoi Ioudaioi</strong> ('the Jews also joined in the accusation'): the congregation of accusers — high priest, delegation of elders, professional orator, and supporting Jewish witnesses — provides collective testimony. In Roman law, multiple witnesses were important; the concurrence appears overwhelming. Paul's response must counter not just the legal argument but the social weight of an entire institutional leadership testifying against him.</p>",

    "10": "<p><strong>Ek pollōn etōn onta se kritēn tō ethnei toutō epistamenos</strong> ('knowing that for many years you have been a judge over this nation'): Paul's <em>captatio benevolentiae</em> is noticeably shorter and more measured than Tertullus's — he compliments Felix's experience rather than his beneficence. Judicial experience is a neutral-positive quality: it implies Felix knows the law, is not easily fooled, and can distinguish genuine evidence from accusation. The appeal to competence rather than generosity is a more restrained and arguably more effective form of judicial appeal.</p>",

    "11": "<p><strong>Ou pleiōn eisin moi hēmerai dōdeka</strong> ('it is not more than twelve days since I went up to worship'): the chronological argument is precise and falsifiable — twelve days is incompatible with the charge of organizing widespread agitation. Paul counts the days from his arrival in Jerusalem (21:15-17 — three days before meeting James) to his arrest. The brevity of the visit, verifiable by the Sanhedrin members themselves, directly undercuts Tertullus's characterization of Paul as a systematic troublemaker 'all over the world.'</p>",

    "12": "<p><strong>Oute en tō hierō heuron me pros tina dialegomonon</strong> ('they did not find me arguing with anyone at the temple'): Paul's triple denial — no arguing at the temple, no stirring up crowds in the synagogues, no creating disturbances anywhere in the city — directly addresses Tertullus's three-part charge (pestilence/troublemaker, leader of a sect, temple desecrator). The legal form mirrors the accusation's structure, a classical rhetorical technique for rebuttal called <em>refutatio</em>.</p>",

    "13": "<p><strong>Oude parastēsai dynantai soi peri hōn nyn katēgorousin mou</strong> ('nor can they prove to you the charges they are now bringing against me'): the burden-of-proof challenge — <em>paristēmi</em> (prove, demonstrate) is a legal term — places the evidentiary burden where Roman law placed it: on the accusers. Paul does not merely deny; he challenges the accusers to produce verifiable evidence. The challenge will go unanswered — the real witnesses (the Asian Jews who made the original accusation) are absent (v.19).</p>",

    "14": "<p><strong>Homotogō de touto soi hoti kata tēn hodon ēn legousin hairesin</strong> ('I admit this to you: according to the Way which they call a sect'): Paul's counter-labeling reappropriates Tertullus's <em>hairesis</em> (v.5) — he accepts the label ('which they call a sect') while stripping it of pejorative force. The Way is not a destructive faction but the fulfillment of the ancestral faith. 'Believing all things in the Law and the Prophets' (<em>pisteuōn pasin tois kata ton nomon kai en tois prophētais gegrammēnois</em>) plants Paul firmly within Israel's canonical tradition — Christianity is not apostasy but fulfillment.</p>",

    "15": "<p><strong>Anastasin mellein esesthai dikaiōn te kai adikōn</strong> ('there will be a resurrection of both the righteous and the wicked'): the universal resurrection — of both righteous and wicked, for judgment — draws from Dan 12:2, the most explicit OT statement of bodily resurrection. The inclusion of the wicked's resurrection distinguishes this from merely a happy afterlife — the resurrection is for accountability, not only for reward. Paul presents this hope as shared with the Pharisees in the Sanhedrin delegation (v.15, 'which these men themselves hold').</p>",

    "16": "<p><strong>Aproskopon syneidēsin echein pros ton theon kai tous anthrōpous dia pantos</strong> ('to maintain a clear conscience before God and man always'): <em>aproskopon</em> (not stumbling, causing no offense) + <em>syneidēsis</em> (conscience) is the same vocabulary cluster Paul uses in his opening statement to the Sanhedrin (23:1). The dual accountability — to God and to the human community — frames Paul's moral life as transparently public. This is Paul's consistent self-presentation in Acts: his behavior is verifiable, his conscience is clean, and he invites scrutiny.</p>",

    "17": "<p><strong>Dia etōn pleionōn eleēmosynas poiēsōn eis to ethnos mou kai prosphoras</strong> ('after several years, bringing charitable gifts and offerings to my nation'): Luke's only reference to Paul's Jerusalem collection — the major organizational project of Paul's third missionary journey that dominates 2 Cor 8-9, Rom 15:25-28, and 1 Cor 16:1-4. The collection was Paul's concrete gesture of Gentile-church solidarity with the Jerusalem community. Luke's restraint in mentioning it (one clause, not elaborated) is itself a historical datum — he chooses to include it as evidence of Paul's good-faith relationship with Jerusalem, not as a theological showcase of inter-church generosity.</p>",

    "18": "<p><strong>Hēgnismenon en tō hierō</strong> ('having completed purification in the temple'): Paul's temple presence was in the context of fulfilled Nazirite vows — the most Jewish possible activity, not desecration. He was in a state of ritual purity (<em>hagnismenon</em>), completing socially approved vow-rituals, when the accusation arose. The original charge of bringing Gentiles into the inner courts (21:28) collapses against the actual circumstances of his visit: he was not bringing Gentiles in but completing Jewish purification acts while in a state of purity himself.</p>",

    "19": "<p><strong>Hous edei epi sou pareinai kai katēgorein ei ti echoien pros eme</strong> ('who ought to be present before you and make an accusation if they have anything against me'): the absent-witnesses argument is Paul's strongest legal point. Roman law required accusers to appear in person — the principle confirmed by Trajan's rescript to Pliny (Ep. 10.97, 'It is not consistent with justice to condemn without accusers present') and implicitly in Lysias's letter (23:30, 'ordering his accusers to present their case before you'). The Asian Jews who originally made the charge are not present; their absence is a procedural deficiency that should end the case under Roman law.</p>",

    "20": "<p><strong>E autoi houtoi eipatōsan ti heuron adikēma</strong> ('or let these men here state what crime they found in me'): Paul invites the present accusers — those who were at the Sanhedrin hearing — to state their case directly. The only specific charge they can offer is the theological statement about resurrection (v.21). Everything else is allegation without witnesses. Paul's advocacy is tight and specific: he forces the accusers to either produce evidence or narrow to the actual substantive disagreement, which is theological rather than criminal.</p>",

    "21": "<p><strong>Peri anastaseōs nekrōn egō krinomai sēmeron eph' hymōn</strong> ('it is concerning the resurrection of the dead that I am on trial today before you'): Paul's self-summary cuts through all the political and procedural complexity to the theological core. The resurrection is the real question; everything else is obscuring it. The statement is simultaneously a legal argument (there is no criminal charge, only a theological dispute) and a theological proclamation (the resurrection is the gospel's center). Paul uses the trial as a platform for proclamation, not merely as a defense.</p>",

    "22": "<p><strong>Akribēsteron eidōs ta peri tēs hodou</strong> ('knowing the Way more accurately'): Felix's knowledge of the Way — whether through Drusilla (v.24), through administrative experience in Judea, or through other sources — is historically plausible. Felix had governed Judea for years (52-60 CE) and would have had extensive contact with the Jewish community and its internal movements. <em>Anebaleato autous</em> ('he adjourned the proceedings'): the formal procedural postponement — neither conviction nor acquittal. Felix's deferral is a judicial non-decision made from political calculation: he cannot convict Paul without evidence, but releasing him would alienate the Jewish leadership he needed for political stability.</p>",

    "23": "<p><strong>Echein te anesin</strong> ('to have some freedom/relief'): Paul's custody is <em>custodia libera</em> (free custody) — supervised but not confined. <em>Mēdena kōlyein tōn idiōn autou hypēretein autō</em> ('no one to prevent his own people from serving him'): the apostolic community could visit, bring resources, and maintain relationship. This arrangement explains how Paul maintained his ministry connections during the Caesarean imprisonment — possibly writing or dictating letters during this period, with Philippians, Philemon, and Colossians among the candidates proposed by various scholars.</p>",

    "24": "<p><strong>Drusilla, gynaiki ousē Ioudaia</strong> ('Drusilla, who was Jewish'): Drusilla was the youngest daughter of Herod Agrippa I (who died in Acts 12:23 — the same man whose death Luke records) and the sister of Agrippa II (who appears in chs. 25-26). She had left her first husband Azizus of Emesa — who had converted to Judaism to marry her — to marry Felix, a Gentile, violating Jewish law on both counts (marriage to an uncircumcised Gentile; abandonment of her first husband). Her Jewish identity made her particularly well-positioned to understand Paul's arguments; her personal history made Paul's speech about righteousness and self-control immediately relevant (v.25).</p>",

    "25": "<p><strong>Peri dikaiosynēs kai enkrateias kai tou krimatos tou mellontos</strong> ('about righteousness, self-control, and the coming judgment'): the three themes are precisely calibrated to Felix and Drusilla's situation. <em>Dikaiosynē</em> (righteousness) before a governor who administered justice corruptly; <em>enkrateia</em> (self-control) to a man who had induced a married woman to leave her husband; <em>krima mellon</em> (the coming judgment) to a man who was misusing his judicial power. <em>Emphobos genomenos</em> ('becoming afraid'): Felix's fear is the recognition of personal moral exposure — the first response of conscience to the gospel's claims. That he sends Paul away rather than responding further shows the fear was insufficient to overcome self-interest.</p>",

    "26": "<p><strong>Chrēmata dothēsetai autō hypo tou Paulou</strong> ('money would be given to him by Paul'): Felix's hope for a bribe reflects the corruption Josephus attests (<em>Ant.</em> 20.8.5; <em>Wars</em> 2.13.2 — 'he exercised the authority of a king with the mentality of a slave'). His frequent conversations with Paul (<em>pyknōteron metepempto auton kai hōmilei autō</em>, 'he sent for him frequently and conversed with him') reveal mixed motives: some genuine interest (perhaps stimulated by Drusilla) and mercenary calculation. The bribe-expectation explains the frequency of conversations: each was an opportunity for Paul to make an offer. Paul's willingness to speak repeatedly to Felix despite the bribe-motivation is his sustained witness to a powerful, sinful audience.</p>",

    "27": "<p><strong>Dietias de plērōtheis ... katēleipen ton Paulon dedemenon charin katathesthai tois Ioudaiois</strong> ('after two years Felix left Paul imprisoned to do a favor to the Jews'): Felix was recalled to Rome around AD 59-60 — Josephus records that he was accused by the Jews of Caesarea and only avoided punishment through the intercession of his brother Pallas at court. His final act — leaving Paul imprisoned as a gift to the Jewish leadership — was a transparently political decision: sacrificing a prisoner's legal rights to maintain political relationships at the end of a troubled tenure. The two years between Paul's arrival in Caesarea and Festus's appointment is the span covered by Acts 23:23-24:27.</p>"
  }
}

def main():
    # INTENT: merge context notes for Acts 22-24 into the shared acts.json output;
    #   merge_comm never overwrites existing verses so this is safe to re-run.
    # CHANGE? If output path changes, update save_comm's source arg and Z_PROGRESS row.
    # VERIFY: console output shows ch22: 30, ch23: 35, ch24: 27 entries.
    existing = load_comm('mkt-context', 'acts')
    merge_comm(existing, ACTS)
    save_comm('mkt-context', 'acts', existing)
    for ch in ['22', '23', '24']:
        count = len(existing.get(ch, {}))
        print(f'  ch{ch}: {count} entries')

if __name__ == '__main__':
    main()
